`,i.jsxs(n.p,{children:["When a process restarts with the same ",i.jsx(n.code,{children:"dataDir"}),", the world reads the in-flight runs (",i.jsx(n.code,{children:"reenqueue_active_runs"}),") and replays them from the durable log. A step whose ",i.jsx(n.code,{children:"StepStatus"})," is already terminal (",i.jsx(n.code,{children:"completed"}),") is ",i.jsx(n.strong,{children:"memoized"})," — its function body never runs again, and the ",i.jsx(n.code,{children:"*_created"})," events that recorded it dedup through a partial ",i.jsx(n.code,{children:"UNIQUE"})," index (",i.jsx(n.code,{children:"ON CONFLICT"}),") so replays never double-write. A step that crashed mid-body is re-enqueued for retry."]}),`
`,i.jsxs(g,{label:"Crash recovery",title:"A restart re-enqueues active runs: terminal steps are memoized, mid-body steps are retried",children:[i.jsxs(b,{label:"Process running",row:!0,children:[i.jsx(d,{kind:"accent",title:"trigger",sub:["run started","events written"]}),i.jsx(l,{dir:"right",kind:"info"}),i.jsx(d,{kind:"success",title:"step A",sub:["terminal","committed to log"]}),i.jsx(l,{dir:"right",kind:"info"}),i.jsx(d,{kind:"error",title:"crash",sub:["mid step B","process exits"]})]}),i.jsx(l,{dir:"down",kind:"warn",dashed:!0,label:"restart · reopen same dataDir"}),i.jsxs(b,{label:"Process restarted — recovery",row:!0,children:[i.jsx(d,{kind:"warn",title:"restart",sub:["reenqueue_active_runs","reopen same dataDir"]}),i.jsx(l,{dir:"right",kind:"accent"}),i.jsx(d,{kind:"accent",title:"replay",sub:["A memoized (skipped)","B retried"]})]}),i.jsx(y,{center:!0,children:"A retry re-executes step B with the same arguments and an incremented attempt; the durable log is the source of truth."})]}),`
